package com.projectbible.post.maven.jdbc.postgresql.auth.presentation;
import com.projectbible.post.maven.jdbc.postgresql.auth.application.AuthService; import com.projectbible.post.maven.jdbc.postgresql.common.api.ApiResponse; import io.swagger.v3.oas.annotations.Operation; import io.swagger.v3.oas.annotations.tags.Tag; import java.util.Map; import org.springframework.web.bind.annotation.*;
@Tag(name="auth") @RestController @RequestMapping("/api/v1/auth") public class AuthController { private final AuthService service; public AuthController(AuthService service) { this.service=service; } @Operation(summary="Login") @PostMapping("/login") public ApiResponse<Map<String,Object>> login(@RequestBody(required=false) Map<String,Object> body) { String email=String.valueOf(body==null?"user@project-bible.dev":body.getOrDefault("email","user@project-bible.dev")); return ApiResponse.success(service.login(email)); } @Operation(summary="Refresh token") @PostMapping("/refresh") public ApiResponse<Map<String,Object>> refresh() { return ApiResponse.success(service.refresh()); } @Operation(summary="Logout") @PostMapping("/logout") public ApiResponse<Map<String,Object>> logout() { return ApiResponse.success(service.logout()); } }
